#header {
  width: 10px;
  height: 20px;
}

.bordered {
  border-top: dotted 1px black;
  border-bottom: solid 2px black;
}

#menu a {
  color: #111;
  .bordered();
}

.post a {
  color: red;
  .bordered();
}

#header {
  color: black;
  .navigation {
    font-size: 12px;
  }
  .logo {
    width: 300px;
  }
}

.button {
  color: blue;
}
.button-ok {
  background-image: url("ok.png");
}
.button:hover {
  color: green;
}

.component {
  width: 300px;
}
@media (min-width: 768px) {
  .component {
    width: 600px;
  }
}
@media (min-width: 768px) and (min-resolution: 192dpi) {
  .component {
    background-image: url(/img/icon2x.png);
  }
}
@media (min-width: 1280px) {
  .component {
    width: 800px;
  }
}

@var: 50vh/2;
width: calc(50% + (@var - 20px));
// 结果是 calc(50% + (25vh - 20px))

@min768: (min-width: 768px);
.element {
  @media @min768 {
    font-size: 1.2rem;
  }
}

@base: #f04615;
@width: 0.5;

.class {
  width: percentage(@width); // 返回 `50%`
  color: saturate(@base, 5%);
  background-color: 
      spin(lighten(@base, 25%), 8);
}

#header a {
  color: orange;
  #bundle.button();
  // 还可以书写为 #bundle > .button 形式
}

.button {
  color: blue;
  border: 1px solid green;
}

@var: red;

#page {
  #header {
    color: @var; // white
  }
  @var: white;
}

/* 一个块注释
 * style comment! */
@var: red;

// 这一行被注释掉了！
@var: white;

nav ul {
  background: blue;
}
.inline,
nav ul {
  color: red;
}

div {
  background: black;
  color: white;
}

